-- Adicionar novos campos
ALTER TABLE follow_ups 
  ADD COLUMN dataFollowUp timestamp NULL AFTER corretorId,
  ADD COLUMN dataRegistro timestamp NULL AFTER dataFollowUp,
  ADD COLUMN resultado enum('respondeu', 'nao_respondeu') NULL AFTER dataRegistro,
  ADD COLUMN observacao text NULL AFTER resultado;

-- Migrar dados: proximaTentativa → dataFollowUp
UPDATE follow_ups SET dataFollowUp = proximaTentativa WHERE dataFollowUp IS NULL;

-- Migrar dados: ultimaTentativa → dataRegistro  
UPDATE follow_ups SET dataRegistro = ultimaTentativa WHERE ultimaTentativa IS NOT NULL;

-- Tornar dataFollowUp NOT NULL após migração
ALTER TABLE follow_ups MODIFY COLUMN dataFollowUp timestamp NOT NULL;

